import './App.css';
import { useMemo, useState } from 'react';

function App() {
  const [taskInput, setTaskInput] = useState('');
  const [tasks, setTasks] = useState([
    { id: 1, text: 'Plan the app structure', completed: false },
    { id: 2, text: 'Build core to-do features', completed: true },
  ]);
  const [filter, setFilter] = useState('all');

  const trimmedInput = taskInput.trim();

  const visibleTasks = useMemo(() => {
    if (filter === 'active') {
      return tasks.filter((task) => !task.completed);
    }

    if (filter === 'completed') {
      return tasks.filter((task) => task.completed);
    }

    return tasks;
  }, [filter, tasks]);

  const completedCount = tasks.filter((task) => task.completed).length;
  const pendingCount = tasks.length - completedCount;

  const addTask = (event) => {
    event.preventDefault();

    if (!trimmedInput) {
      return;
    }

    setTasks((prevTasks) => [
      ...prevTasks,
      {
        id: Date.now(),
        text: trimmedInput,
        completed: false,
      },
    ]);
    setTaskInput('');
  };

  const toggleTask = (id) => {
    setTasks((prevTasks) =>
      prevTasks.map((task) =>
        task.id === id ? { ...task, completed: !task.completed } : task,
      ),
    );
  };

  const deleteTask = (id) => {
    setTasks((prevTasks) => prevTasks.filter((task) => task.id !== id));
  };

  const clearCompleted = () => {
    setTasks((prevTasks) => prevTasks.filter((task) => !task.completed));
  };

  return (
    <main className="todo-app">
      <section className="todo-card" aria-label="To-do list app">
        <header className="todo-header">
          <p className="todo-kicker">Daily Focus</p>
          <h1>To-Do List</h1>
          <p className="todo-subtitle">Organize your day and keep momentum.</p>
        </header>

        <form className="todo-form" onSubmit={addTask}>
          <label htmlFor="task-input" className="sr-only">
            Add a task
          </label>
          <input
            id="task-input"
            type="text"
            value={taskInput}
            onChange={(event) => setTaskInput(event.target.value)}
            placeholder="What do you need to do?"
          />
          <button type="submit" disabled={!trimmedInput}>
            Add Task
          </button>
        </form>

        <div className="todo-toolbar">
          <div className="filters" role="group" aria-label="Filter tasks">
            <button
              type="button"
              className={filter === 'all' ? 'active' : ''}
              onClick={() => setFilter('all')}
            >
              All
            </button>
            <button
              type="button"
              className={filter === 'active' ? 'active' : ''}
              onClick={() => setFilter('active')}
            >
              Active
            </button>
            <button
              type="button"
              className={filter === 'completed' ? 'active' : ''}
              onClick={() => setFilter('completed')}
            >
              Completed
            </button>
          </div>

          <button
            type="button"
            className="clear-btn"
            onClick={clearCompleted}
            disabled={completedCount === 0}
          >
            Clear Completed
          </button>
        </div>

        <ul className="task-list" aria-live="polite">
          {visibleTasks.length === 0 ? (
            <li className="empty-state">No tasks in this view.</li>
          ) : (
            visibleTasks.map((task) => (
              <li key={task.id} className="task-item">
                <label>
                  <input
                    type="checkbox"
                    checked={task.completed}
                    onChange={() => toggleTask(task.id)}
                  />
                  <span className={task.completed ? 'done' : ''}>{task.text}</span>
                </label>
                <button type="button" onClick={() => deleteTask(task.id)}>
                  Delete
                </button>
              </li>
            ))
          )}
        </ul>

        <footer className="todo-footer">
          <p>
            <strong>{pendingCount}</strong> pending
          </p>
          <p>
            <strong>{completedCount}</strong> completed
          </p>
        </footer>
      </section>
    </main>
  );
}

export default App;
